/* Watchdog timer HAL */
#ifndef WDT_HAL_H
#define WDT_HAL_H

#include <stdint.h>

/* Initialize watchdog with timeout in milliseconds.
 * Returns 0 on success, negative error code on failure. */
int wdt_init(uint32_t timeout_ms);

/* Pet/kick the watchdog to prevent reset */
void wdt_kick(void);

/* Disable the watchdog (if permitted by hardware) */
void wdt_disable(void);

/* Get remaining time before reset in ms */
uint32_t wdt_remaining_ms(void);

#endif

